import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.CGYl2SZ_.js";const l=JSON.parse('{"title":"flags","description":"flags 页面","frontmatter":{"title":"flags","description":"flags 页面"},"headers":[],"relativePath":"tools/diagnostics/flags.md","filePath":"tools/diagnostics/flags.md"}');const e=s({name:"tools/diagnostics/flags.md"},[["render",function(s,l,e,n,h,p){return a(),i("div",null,[...l[0]||(l[0]=[t('<h1 id="诊断标志" tabindex="-1">诊断标志 <a class="header-anchor" href="#诊断标志" aria-label="Permalink to &quot;诊断标志&quot;">​</a></h1><p>诊断标志让你能够有针对性地启用调试日志，而无需在任何地方打开详细日志记录。标志是选择加入的，除非子系统检查它们，否则没有效果。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><ul><li>标志是字符串（不区分大小写）。</li><li>你可以在配置中启用标志或通过环境变量覆盖。</li><li>支持通配符： <ul><li><code>telegram.*</code> 匹配 <code>telegram.http</code></li><li><code>*</code> 启用所有标志</li></ul></li></ul><h2 id="通过配置启用" tabindex="-1">通过配置启用 <a class="header-anchor" href="#通过配置启用" aria-label="Permalink to &quot;通过配置启用&quot;">​</a></h2><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;diagnostics&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;flags&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram.http&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>多个标志：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;diagnostics&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;flags&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;telegram.http&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gateway.*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>更改标志后重启网关。</p><h2 id="环境变量覆盖-一次性" tabindex="-1">环境变量覆盖（一次性） <a class="header-anchor" href="#环境变量覆盖-一次性" aria-label="Permalink to &quot;环境变量覆盖（一次性）&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_DIAGNOSTICS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">telegram.http,telegram.payload</span></span></code></pre></div><p>禁用所有标志：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_DIAGNOSTICS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span></span></code></pre></div><h2 id="日志去向" tabindex="-1">日志去向 <a class="header-anchor" href="#日志去向" aria-label="Permalink to &quot;日志去向&quot;">​</a></h2><p>标志将日志发送到标准诊断日志文件。默认：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tmp/openclaw/openclaw-YYYY-MM-DD.log</span></span></code></pre></div><p>如果你设置了 <code>logging.file</code>，请改用该路径。日志是 JSONL（每行一个 JSON 对象）。基于 <code>logging.redactSensitive</code> 仍然应用编辑。</p><h2 id="提取日志" tabindex="-1">提取日志 <a class="header-anchor" href="#提取日志" aria-label="Permalink to &quot;提取日志&quot;">​</a></h2><p>选择最新的日志文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/openclaw/openclaw-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><p>过滤 Telegram HTTP 诊断：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;telegram http error&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/openclaw/openclaw-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.log</span></span></code></pre></div><p>或在复现时跟踪：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/openclaw/openclaw-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%F</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;telegram http error&quot;</span></span></code></pre></div><p>对于远程网关，你也可以使用 <code>openclaw logs --follow</code>（请参阅 <a href="/cli/logs.html">/cli/logs</a>）。</p><h2 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h2><ul><li>如果 <code>logging.level</code> 设置高于 <code>warn</code>，这些日志可能会被抑制。默认的 <code>info</code> 没问题。</li><li>留下启用标志是安全的；它们只会影响特定子系统的日志量。</li><li>使用 <a href="/logging.html">/logging</a> 更改日志目标、级别和编辑。</li></ul>',27)])])}]]);export{l as __pageData,e as default};
